VALUES
  ('pukao-6f0ba476-moex-00179', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲乙為夫妻，無子女，父母雙亡。甲有兄弟丙、丁二人。甲乙約定分別財產制。甲死亡時，留有 遺產新臺幣（下同）600萬元。丙之特留分為何？', '["300萬元", "150萬元", "100萬元", "50萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b0f5ef0fb817", "answer_pdf_sha1": "42b7383a4776", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00180', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲乙為夫妻，有丙、丁二子。丙與戊女結婚有一子己。某日甲丙出差，因事故同時死亡。何者對 甲之遺產有繼承權？', '["乙、丙、丁", "乙、丁、戊", "乙、丁、己", "乙、丙、丁、戊、己"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b0f5ef0fb817", "answer_pdf_sha1": "42b7383a4776", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00181', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列關於表見代理之敘述，何者錯誤？', '["表見代理人為代理行為時，欠缺代理權", "本人知他人表示為其代理人而不為反對之表示者，對於第三人應負授權人之責任", "相對人明知代理人無代理權限者，不成立表見代理", "表見代理之規定，於契約行為及侵權行為均適用之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b0f5ef0fb817", "answer_pdf_sha1": "42b7383a4776", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00182', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '依民法規定，下列關於定金之敘述，何者正確？', '["定金為當事人約定於債務人不履行債務或為不適當之履行時，應支付之金錢", "訂約當事人一方，由他方受有定金時，視為契約成立", "契約因可歸責於付定金當事人之事由，致不能履行時，定金不得請求返還", "契約因可歸責於受定金當事人之事由，致不能履行時，該當事人僅應返還其所受定金"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b0f5ef0fb817", "answer_pdf_sha1": "42b7383a4776", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00183', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲、乙二人駕駛轎車，因雙方之過失發生碰撞，導致甲之轎車受有新臺幣（下同）30萬元之損害， 乙之轎車受有20萬元之損害。下列敘述，何者正確？', '["僅甲得主張抵銷", "僅乙得主張抵銷", "甲、乙均得主張抵銷", "甲、乙均不得主張抵銷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b0f5ef0fb817", "answer_pdf_sha1": "42b7383a4776", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00184', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲以遺囑將其所有之A屋與B地遺贈友人乙。甲於民國（下同）112年1月1日死亡，乙於同年2月1 日始知受遺贈，於同日向甲之繼承人表示拋棄遺贈。該拋棄遺贈之效力如何？', '["自112年2月1日生效", "溯及於112年1月1日生效", "須待乙以書面向法院辦理拋棄遺贈，並經法院許可時起生效", "須待乙以書面向法院辦理拋棄遺贈，始溯及於112年1月1日生效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b0f5ef0fb817", "answer_pdf_sha1": "42b7383a4776", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
