  ('pukao-6f0ba476-moex-00187', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '有關徵收期間的規定，下列何者錯誤？', '["徵收期間是指對已確定之稅款，行使徵收權的期間", "稅捐之徵收期間為五年，自繳納期間屆滿之翌日起算", "稅捐之徵收，於徵收期間屆滿前已移送執行但未開始執行者，自徵收期間屆滿之翌日起，不得 再執行", "應徵之稅捐未於徵收期間徵起者，除特別規定，不得再行徵收"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b5d36143eef6", "answer_pdf_sha1": "cd7aba67d90c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
